/**
 * Returns all templates across all calculator categories.
 * Used by the generator to produce all variant pages.
 */
export function getAllTemplates(): VariantTemplate[] {
  return variantTemplates;
}

/**
 * Get templates for a specific calculator ID.
 */
export function getTemplatesByCalculator(calculatorId: string): VariantTemplate | undefined {
  return variantTemplates.find((t) => t.calculatorId === calculatorId);
}
